import json
import psycopg2

def lambda_handler(event, context):
    conn_string = "postgresql://admin:password@internal-db.us-east-1.rds.amazonaws.com:5432/production"
    
    try:
        conn = psycopg2.connect(conn_string)
        cursor = conn.cursor()
        
        # Example query
        cursor.execute("SELECT * FROM your_table")
        records = cursor.fetchall()
        
        result = []
        for record in records:
            result.append(dict(zip([desc[0] for desc in cursor.description], record)))
        
        return {
            'statusCode': 200,
            'body': json.dumps(result)
        }
    
    except psycopg2.Error as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }
    
    finally:
        if conn:
            cursor.close()
            conn.close()